INSERT INTO public.trs_nodes
(id, node_json, tenant_id, created_by, "order", created_at, updated_at)
VALUES(34, '{"name": "Standard Deviation", "type": "function", "color": "#9C27B0", "label": "Standard Deviation", "modes": {"call": {"label": "Call: Standard Deviation", "inputs": [{"key": "storeResult", "type": "checkbox", "label": "Store result in variable", "defaultValue": "true"}, {"key": "resultVariable", "type": "text", "label": "Result variable name", "placeholder": "result", "defaultValue": "stdDev"}], "handles": {"source": true, "target": true}, "visible_on_canvas": ["nested"], "useDefinitionParameters": true}, "definition": {"label": "Define: Standard Deviation", "inputs": [{"key": "code_template", "type": "code", "label": "Function Code", "required": true, "placeholder": "Enter function code...", "defaultValue": "export const standardDeviation = (values: number[]): number => {\n  const n = values.length;\n  if (n === 0) return 0;\n  \n  const mean = values.reduce((sum, val) => sum + val, 0) / n;\n  const squaredDiffs = values.map(val => Math.pow(val - mean, 2));\n  const variance = squaredDiffs.reduce((sum, val) => sum + val, 0) / n;\n  \n  return Math.sqrt(variance);\n};"}], "handles": {"source": true, "target": true}, "parameters": [{"name": "values", "type": "number[]", "label": "Array of values"}], "code_template": "${params.code_template}", "visible_on_canvas": ["main"]}}, "category": "rule_builder", "node_type": "StandardDeviation", "description": "Calculate standard deviation of an array of numbers", "default_data": {}, "function_name": "standardDeviation", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-01-19', '2026-01-19');
