INSERT INTO public.trs_nodes
(id, node_json, tenant_id, created_by, "order", created_at, updated_at)
VALUES(17, '{"name": "Haversine Distance", "type": "function", "color": "#9C27B0", "label": "Haversine Distance", "modes": {"call": {"label": "Call: Haversine Distance", "inputs": [{"key": "storeResult", "type": "checkbox", "label": "Store result in variable", "defaultValue": "true"}, {"key": "resultVariable", "type": "text", "label": "Result variable name", "placeholder": "result", "defaultValue": "distance"}], "handles": {"source": true, "target": true}, "visible_on_canvas": ["nested"], "useDefinitionParameters": true}, "definition": {"label": "Define: Haversine Distance", "inputs": [{"key": "code_template", "type": "code", "label": "Function Code", "required": true, "placeholder": "Enter function code...", "defaultValue": "const toRadians = (degrees: number): number => {\n  return degrees * (Math.PI / 180);\n};\n\nexport const haversineDistance = (lat1: number, lat2: number, long1: number, long2: number): number => {\n  const radius = 6371;\n\n  const deltaLat = toRadians(lat2 - lat1);\n  const deltaLong = toRadians(long2 - long1);\n\n  const lat1Rad = toRadians(lat1);\n  const lat2Rad = toRadians(lat2);\n\n  const havTheta = Math.pow(Math.sin(deltaLat / 2), 2) + Math.pow(Math.sin(deltaLong / 2), 2) * Math.cos(lat1Rad) * Math.cos(lat2Rad);\n\n  const theta = 2 * Math.asin(Math.sqrt(havTheta));\n  const distance = theta * radius;\n\n  return distance;\n};"}], "handles": {"source": true, "target": true}, "parameters": [{"name": "lat1", "type": "number", "label": "Latitude 1"}, {"name": "lat2", "type": "number", "label": "Latitude 2"}, {"name": "long1", "type": "number", "label": "Longitude 1"}, {"name": "long2", "type": "number", "label": "Longitude 2"}], "code_template": "${params.code_template}", "visible_on_canvas": ["main"]}}, "category": "rule_builder", "node_type": "HaversineDistance", "description": "Calculate distance between two GPS coordinates", "default_data": {}, "function_name": "haversineDistance", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', '0', '2026-01-19', '2026-01-19');
