VALUES(40, '{"name": "Outcome Test Band 02 (maxQueryRange omitted)", "type": "function", "color": "#9C27B0", "label": "Outcome Test Band 02 (maxQueryRange omitted)", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": ".02 result omitted maxQueryRange parameter"}, {"key": "dbData", "type": "text", "label": "DB Data Array", "required": true, "placeholder": "Enter array of values (e.g., [1000, 2000, 3000])", "defaultValue": "[2000, 2022, 50000]"}, {"key": "expectStatement", "type": "textarea", "label": "Expect Statement", "required": true, "placeholder": "Enter expect statement", "defaultValue": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\", \"tenantId\": \"DEFAULT\",\"cfg\":\"1.0.0\",\"subRuleRef\":\".02\",\"reason\":\"The creditor has received a significant number of transactions with the same amount in the last 24 hours\"}'',\n  ),\n);"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "OutcomeTestBand02MaxQueryRangeOmitted", "description": "Test node for band .02 validation with maxQueryRange parameter omitted", "default_data": {"dbData": "[2000, 2022, 50000]", "testName": ".02 result omitted maxQueryRange parameter", "expectStatement": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\", \"tenantId\": \"DEFAULT\",\"cfg\":\"1.0.0\",\"subRuleRef\":\".02\",\"reason\":\"The creditor has received a significant number of transactions with the same amount in the last 24 hours\"}'',\n  ),\n);"}, "isPredefined": true, "code_template": "test(''${params.testName}'', async () => {\n${indent}  const dbData = ${params.dbData};\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({\n${indent}    rows: [\n${indent}      ...dbData.map((x) => ({\n${indent}        Amt: x,\n${indent}      })),\n${indent}    ],\n${indent}  });\n${indent}  const rConfig = getRuleConfig();\n${indent}  rConfig.config.parameters!.maxQueryRange = undefined;\n${indent}  const res = await handleTransaction(req, determineOutcome, ruleResult, loggerService, rConfig, databaseManager);\n${indent}  ${params.expectStatement}\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-02-04', '2026-02-04');
