VALUES(46, '{"name": "Error Test: Bad or missing subRuleRef for \".x01\"", "type": "function", "color": "#9C27B0", "label": "Error Test: Bad or missing subRuleRef for \".x01\"", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": "No exit conditions - bad or missing subRuleRef for \".x01\""}, {"key": "dbData", "type": "text", "label": "DB Data Array", "required": true, "placeholder": "Enter array of values (e.g., [1000, 2000, 3000])", "defaultValue": "[50]"}, {"key": "successExpectStatement", "type": "textarea", "label": "Success Expect Statement", "required": true, "placeholder": "Enter expect statement for success case", "defaultValue": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\",\"tenantId\": \"DEFAULT\", \"cfg\":\"1.0.0\",\"desc\":\"No description provided in rule config.\",\"subRuleRef\":\".x00\",\"reason\":\"Incoming transaction is unsuccessful\"}'',\n  ),\n);"}, {"key": "errorExpectStatement", "type": "textarea", "label": "Error Expect Statement", "required": true, "placeholder": "Enter expect statement for error case", "defaultValue": "expect((error as Error).message).toBe(''Insufficient History and no exit condition in config'');"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "ErrorTestBadOrMissingSubRuleRefX01", "description": "Test node for error handling when exit condition .x01 has bad or missing subRuleRef", "default_data": {"dbData": "[50]", "testName": "No exit conditions - bad or missing subRuleRef for \".x01\"", "errorExpectStatement": "expect((error as Error).message).toBe(''Insufficient History and no exit condition in config'');", "successExpectStatement": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\",\"tenantId\": \"DEFAULT\", \"cfg\":\"1.0.0\",\"desc\":\"No description provided in rule config.\",\"subRuleRef\":\".x00\",\"reason\":\"Incoming transaction is unsuccessful\"}'',\n  ),\n);"}, "isPredefined": true, "code_template": "test(''${params.testName}'', async () => {\n${indent}  const dbData = ${params.dbData};\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({\n${indent}    rows: [\n${indent}      ...dbData.map((x) => ({\n${indent}        Amt: x,\n${indent}      })),\n${indent}    ],\n${indent}  });\n${indent}  try {\n${indent}    const rConfig = getRuleConfig();\n${indent}    const newReq = getMockRequest();\n${indent}    rConfig.config.exitConditions![1].subRuleRef = '''';\n${indent}    const res = await handleTransaction(newReq, determineOutcome, ruleResult, loggerService, rConfig, databaseManager);\n${indent}    ${params.successExpectStatement}\n${indent}  } catch (error) {\n${indent}    ${params.errorExpectStatement}\n${indent}  }\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-02-04', '2026-02-04');
