VALUES(47, '{"name": "Error Test: No tolerance", "type": "function", "color": "#9C27B0", "label": "Error Test: No tolerance", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": "No tolerance"}, {"key": "dbData", "type": "text", "label": "DB Data Array", "required": true, "placeholder": "Enter array of values (e.g., [1000, 2000, 3000])", "defaultValue": "[1, 2, 3]"}, {"key": "expectStatement", "type": "textarea", "label": "Expect Statement", "required": true, "placeholder": "Enter expect statement for error handling", "defaultValue": "expect((error as Error).message).toBe(''Invalid config provided - tolerance parameter not provided or invalid type'');"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "ErrorTestNoTolerance", "description": "Test node for error handling when tolerance parameter is not provided", "default_data": {"dbData": "[1, 2, 3]", "testName": "No tolerance", "expectStatement": "expect((error as Error).message).toBe(''Invalid config provided - tolerance parameter not provided or invalid type'');"}, "isPredefined": true, "code_template": "test(''${params.testName}'', async () => {\n${indent}  // Mocking the request of getting oldes transation timestamp\n${indent}  const dbData = ${params.dbData};\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({\n${indent}    rows: [\n${indent}      ...dbData.map((x) => ({\n${indent}        Amt: x,\n${indent}      })),\n${indent}    ],\n${indent}  });\n${indent}  try {\n${indent}    const rConfig = getRuleConfig();\n${indent}    rConfig.config.parameters!.tolerance = undefined;\n${indent}    await handleTransaction(req, determineOutcome, ruleResult, loggerService, rConfig, databaseManager);\n${indent}  } catch (error) {\n${indent}    ${params.expectStatement}\n${indent}  }\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-95