VALUES(36, '{"name": "Import Statement Node", "type": "basic", "color": "#9C27B0", "label": "Import", "inputs": [{"key": "importStatement", "type": "textarea", "label": "Import Statement", "required": true, "placeholder": "import { } from ''''", "defaultValue": "/* eslint-disable @typescript-eslint/no-unused-vars */\nimport { type DataCache, type RuleConfig, type RuleRequest, type RuleResult } from ''@tazama-lf/frms-coe-lib/lib/interfaces'';\nimport {\n  DatabaseManagerMock,\n  determineOutcome,\n  LoggerServiceMock,\n  MockDatabaseManagerFactory,\n  MockLoggerServiceFactory,\n} from ''@tazama-lf/frms-coe-lib/lib/tests/mocks'';"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "Import", "description": "Imports modules for test cases", "default_data": {"importStatement": "/* eslint-disable @typescript-eslint/no-unused-vars */\nimport { type DataCache, type RuleConfig, type RuleRequest, type RuleResult } from ''@tazama-lf/frms-coe-lib/lib/interfaces'';\nimport {\n  DatabaseManagerMock,\n  determineOutcome,\n  LoggerServiceMock,\n  MockDatabaseManagerFactory,\n  MockLoggerServiceFactory,\n} from ''@tazama-lf/frms-coe-lib/lib/tests/mocks'';"}, "code_template": "${params.importStatement || ''''}", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-01-30', '2026-01-30');
INSERT INTO public.trs_nodes
(id, node_json, tenant_id, created_by, "order", created_at, updated_at)
VALUES(39, '{"name": "Outcome Test Exit X00 unsuccessful transaction", "type": "function", "color": "#9C27B0", "label": "Outcome Test Exit X00", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": ".x00 Rule return -> ''Unsuccessful transaction''"}, {"key": "expectStatement", "type": "textarea", "label": "Expect Statement", "required": true, "placeholder": "Enter expect statement", "defaultValue": "expect(res).toEqual(\n  JSON.parse(''{\"id\":\"021@1.0.0\", \"cfg\":\"1.0.0\",\"subRuleRef\":\".x00\",\"reason\":\"Unsuccessful transaction\", \"tenantId\": \"DEFAULT\"}''),\n);"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "OutcomeTestExitX00", "description": "Test node for exit condition .x00 with unsuccessful transaction", "default_data": {"testName": ".x00 Rule return -> ''Unsuccessful transaction''", "expectStatement": "expect(res).toEqual(\n  JSON.parse(''{\"id\":\"021@1.0.0\", \"cfg\":\"1.0.0\",\"subRuleRef\":\".x00\",\"reason\":\"Unsuccessful transaction\", \"tenantId\": \"DEFAULT\"}''),\n);"}, "isPredefined": true, "code_template": "test(\"${params.testName}\", async () => {\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({ rows: [] });\n${indent}  const req = getMockRequestUnsuccessful();\n${indent}  const res = await handleTransaction(req, determineOutcome, ruleResult, loggerService, getRuleConfig(), databaseManager);\n${indent}  ${params.expectStatement}\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-02-04', '2026-02-04');
INSERT INTO public.trs_nodes
