VALUES(42, '{"name": "Error Test Missing bands throws", "type": "function", "color": "#9C27B0", "label": "Error Test Missing bands throws", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": "No RuleConfig - bands"}, {"key": "dbData", "type": "text", "label": "DB Data Array", "required": true, "placeholder": "Enter array of values (e.g., [1000, 2000, 3000])", "defaultValue": "[1]"}, {"key": "expectStatement", "type": "textarea", "label": "Expect Statement", "required": true, "placeholder": "Enter expect statement for error handling", "defaultValue": "expect((error as Error).message).toBe(''Invalid config provided - bands not provided'');"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "ErrorTestMissingBandsThrows", "description": "Test node for error handling when bands config is missing", "default_data": {"dbData": "[1]", "testName": "No RuleConfig - bands", "expectStatement": "expect((error as Error).message).toBe(''Invalid config provided - bands not provided'');"}, "isPredefined": true, "code_template": "test(''${params.testName}'', async () => {\n${indent}  const dbData = ${params.dbData};\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({\n${indent}    rows: [\n${indent}      ...dbData.map((x) => ({\n${indent}        Amt: x,\n${indent}      })),\n${indent}    ],\n${indent}  });\n${indent}  const rConfig = getRuleConfig();\n${indent}  rConfig.config.bands = undefined;\n${indent}  try {\n${indent}    await handleTransaction(req, determineOutcome, ruleResult, loggerService, rConfig, databaseManager);\n${indent}  } catch (error) {\n${indent}    ${params.expectStatement}\n${indent}  }\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-02-04', '2026-02-04');
