INSERT INTO public.trs_nodes
(id, node_json, tenant_id, created_by, "order", created_at, updated_at)
VALUES(48, '{"name": "Error Test: Bad or missing subRuleRef for \".x00\"", "type": "function", "color": "#9C27B0", "label": "Error Test: Bad or missing subRuleRef for \".x00\"", "inputs": [{"key": "testName", "type": "text", "label": "Test Name", "required": true, "placeholder": "Enter test description", "defaultValue": "No exit conditions - bad or missing subRuleRef for \".x00\""}, {"key": "successExpectStatement", "type": "textarea", "label": "Success Expect Statement", "required": true, "placeholder": "Enter expect statement for success case", "defaultValue": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\", \"tenantId\": \"DEFAULT\",\"cfg\":\"1.0.0\",\"desc\":\"No description provided in rule config.\",\"subRuleRef\":\".x00\",\"reason\":\"Incoming transaction is unsuccessful\"}'',\n  ),\n);"}, {"key": "errorExpectStatement", "type": "textarea", "label": "Error Expect Statement", "required": true, "placeholder": "Enter expect statement for error case", "defaultValue": "expect((error as Error).message).toBe(''Unsuccessful transaction and no exit condition in config'');"}], "handles": {"source": true, "target": true}, "category": "test_case_generation", "node_type": "ErrorTestBadOrMissingSubRuleRefX00", "description": "Test node for error handling when exit condition has bad or missing subRuleRef", "default_data": {"testName": "No exit conditions - bad or missing subRuleRef for \".x00\"", "errorExpectStatement": "expect((error as Error).message).toBe(''Unsuccessful transaction and no exit condition in config'');", "successExpectStatement": "expect(res).toEqual(\n  JSON.parse(\n    ''{\"id\":\"021@1.0.0\", \"tenantId\": \"DEFAULT\",\"cfg\":\"1.0.0\",\"desc\":\"No description provided in rule config.\",\"subRuleRef\":\".x00\",\"reason\":\"Incoming transaction is unsuccessful\"}'',\n  ),\n);"}, "isPredefined": true, "code_template": "test(''${params.testName}'', async () => {\n${indent}  databaseManager._eventHistory.query.mockResolvedValue({ rows: [] });\n${indent}  try {\n${indent}    const rConfig = getRuleConfig();\n${indent}    const newReq = getMockRequest();\n${indent}    newReq.transaction.FIToFIPmtSts.TxInfAndSts.TxSts = ''.x00'';\n${indent}    rConfig.config.exitConditions![0].subRuleRef = '''';\n${indent}    rConfig.config.parameters!.maxQueryLimit = 2;\n${indent}    rConfig.config.parameters!.tolerance = 0.1;\n${indent}    const res = await handleTransaction(newReq, determineOutcome, ruleResult, loggerService, rConfig, databaseManager);\n${indent}    ${params.successExpectStatement}\n${indent}  } catch (error) {\n${indent}    ${params.errorExpectStatement}\n${indent}  }\n${indent}});", "visible_on_canvas": ["main"]}'::jsonb, 'DEFAULT', '1b7f59dd-8754-48eb-9573-65d106951635', NULL, '2026-02-04', '2026-02-04');
